-
-        for url in candidates {
-            do {
-                let size = (try? FileManager.default.attributesOfItem(atPath: url.path)[.size] as? NSNumber)?.intValue
-                logger?("Safari cookies: trying \(url.path) (\(size ?? -1) bytes)")
-                let data = try Data(contentsOf: url)
